"use strict";(()=>{const btn=document.querySelector(".copy-email-btn");if(!btn)return;const emailLink=document.querySelector('a[href^="mailto:"]');if(!emailLink)return;const email=emailLink.href.replace("mailto:","");btn.addEventListener("click",()=>{navigator.clipboard.writeText(email).then(()=>{btn.classList.add("copied"),btn.setAttribute("aria-label","Email copied!"),setTimeout(()=>{btn.classList.remove("copied"),btn.setAttribute("aria-label","Copy email to clipboard")},2e3)})})})(),function(){const $root=document.querySelector("html"),$langToggle=document.querySelector(".lang-toggle"),languages=["en","ru","uk"];$langToggle.addEventListener("click",function(){$root.setAttribute("lang",function(){const currentLanguageIndex=languages.indexOf($root.getAttribute("lang"));return languages[currentLanguageIndex+1]||languages[0]}())},!1)}(),(()=>{const toggle=document.querySelector(".reading-mode-toggle");if(!toggle)return;const html=document.documentElement,currentTheme=html.getAttribute("data-theme")||"light";toggle.setAttribute("aria-pressed",String("dark"===currentTheme)),toggle.addEventListener("click",()=>{const next="dark"===(html.getAttribute("data-theme")||"light")?"light":"dark";html.setAttribute("data-theme",next),localStorage.setItem("theme",next),toggle.setAttribute("aria-pressed",String("dark"===next))})})();